-- 1. Guidebook row (upsert by slug).
insert into guidebooks (slug, property_name, host_name, host_phone, host_photo_url, welcome_html, street_name, street_number, city, country_code, postal_code, hero_image_url, checkin_text, directions_text, parking_text, wifi_ssid, wifi_password, wifi_notes, checkout_text, lat, lng, armed_response_company, armed_response_phone, nearest_hospital_name, nearest_hospital_phone, nearest_hospital_address, is_published) values (
  $gb$montrose-terrace$gb$, $gb$9 Montrose Terrace$gb$, $gb$Hayley Harrod$gb$, $gb$+27 83 415 7779$gb$, $gb$https://storage.googleapis.com/hostfully-dev-filestack/G4TbbjJSeiRDgp8ufHUn$gb$, $gb$<p>We hope you have a wonderful stay and enjoy all Cape Town has to offer.</p><p>If you have any issues please consult the guidebook first.</p><p>We are also contactable for emergencies.</p><p>Please contact <span style="color: rgba(0, 0, 0, 0.87);">Hayley (+27 83 415 7779) </span> first and alternatively Nicki (+27 83 595 4103)</p>$gb$, $gb$Montrose Terrace$gb$, $gb$9$gb$, $gb$Cape Town$gb$, $gb$ZA$gb$, $gb$7806$gb$, $gb$https://storage.googleapis.com/hostfully-dev-filestack/JkBSQ7SWQvexpJGJoLDe$gb$, $gb$<p>Check-in from <strong>2:00 PM</strong>.</p><p>Please text Hayley (+ 27 83 415 7779) as you leave the airport and someone will meet you at the house to show you around.</p>$gb$, $gb$<p><strong>From the airport</strong></p><p>Cape Town International Airport Matroosfontein, Cape Town, 7490 Follow Ring Rd and Airport Approach Rd to Settlers Way/N2 in Kanana 5 min (4.0 km) Head northeast on Ring Rd 700 m Continue straight to stay on Ring Rd 350 m Use the left 2 lanes to stay on Ring Rd 650 m Use the right 2 lanes to turn slightly left toward Airport Approach Rd 180 m Use the right 2 lanes to merge onto Airport Approach Rd 190 m Keep right to stay on Airport Approach Rd 1.9 km Continue on Settlers Way/N2 to Rondebosch 10 min (12.5 km) Merge onto Settlers Way/N2 10.2 km Take exit 6 for M3/Rhodes Drive toward Observatory/Muizenberg 350 m Merge onto Rhodes Dr/M3 2.0 km Continue on M3. Take Rhodes Ave/M63 to Montrose Terrace in Constantia Heights 8 min (5.8 km) Use the middle lane to stay on Rhodes Dr/M3 Continue to follow M3 1.1 km Keep left to continue on Union Ave/M3 750 m Turn right onto Rhodes Ave/M63 2.5 km Turn right onto Rhodes Dr/M63 450 m Turn left onto Klaasens Rd 550 m Turn right onto Montrose Ave 140 m Turn right onto Montrose Terrace Destination will be on the left 300 m 9 Montrose Terrace Constantia Heights, Cape Town, 7806</p>$gb$, $gb$<p>Parking in garage for 3 cars Driveway parking for 2 cars Please note that the housekeeper parks his own car on the property (Toyota Tazz) in an allocated space which should not interfere with guests own parking</p>$gb$, $gb$Montrose$gb$, $gb$Yianni6501$gb$, null, $gb$<p>Check-out by <strong>10:00 AM</strong>.</p><p>Hayley or Tanna will be in touch the day before check out to arrange a time to meet at the house for your departure</p>$gb$, -33.9958979, 18.4308997, $gb$Prosec Security$gb$, $gb$021 712 4009$gb$, $gb$Mediclinic Constantiaberg$gb$, null, $gb$Mediclinic Constantiaberg, Burnham Rd, Plumstead, Cape Town$gb$, true
