-- 3. House-manual library rows.
insert into guidebook_house_manuals (slug, title, category, body_html, icon, image_url, emergency_tag) values
  ($gb$montroseterrace-keys-and-entry$gb$, $gb$Keys and Entry$gb$, $gb$Access$gb$, $gb$<p><em>Black Remote x 2</em></p><p><em>Blue button - to open & close driveway gate (please note not on auto close & must be done manually)</em></p><p><em>Green button - to open & close garage door,</em></p><p><em>Red button – Alarm panic button & will set alarm siren off with armed response callout</em></p><p><em>Yellow Button – Arm & Disarm external Beams only</em></p><p><em>White button – Arm & Disarm House Alarm</em></p>$gb$, $gb$key$gb$, null, null),
  ($gb$montroseterrace-alarm-and-locking-up$gb$, $gb$Alarm and Locking Up$gb$, $gb$Access$gb$, $gb$<p>·     <em>Who is the security company? Prosec Security – 021 7124009 (control room)</em></p><p>·     <em>What is the password? TWINS (to be used for armed response when they call at the house after an alarm activation)</em></p><p><br /></p><p><em>The house is equipped with an alarm and beams which John can set at night</em></p>$gb$, $gb$shield$gb$, null, null),
  ($gb$montroseterrace-house-rules$gb$, $gb$House Rules$gb$, $gb$House Rules$gb$, $gb$<p>·     <em>no smoking</em></p><p>·     <em>no food in bedrooms</em></p><p>·     <em>any equipment they shouldn’t use – ride on lawnmower</em></p><p>·     <em>No foreign objects or sanitary pads to be disposed of in toilets – Soakaway</em></p>$gb$, $gb$home$gb$, null, null),
  ($gb$montroseterrace-staff$gb$, $gb$Staff$gb$, $gb$Local Context$gb$, $gb$<p>o  <em>John and Magnes – (husband & wife who live on the property) cell number 078 0809543 and as arranged will work every day</em></p><p>·     Their roles include <em>washing, ironing, making beds, vacuuming, dusting, cleaning bathrooms.</em></p><p><em>Working Hours</em><br /><em>Monday to Friday 8am to 5pm </em><br /><em>Weekends and Public Holidays 9am to 2pm</em><br /></p><p>·     <em>John & Magnes have been on the property for 9 years so know the property well. You can arrange to have John arm and disarm the alarm beams at night after a certain time as an additional security measure.</em></p>$gb$, $gb$home$gb$, null, null),
  ($gb$montroseterrace-kitchen-appliances$gb$, $gb$Kitchen Appliances$gb$, $gb$Appliances$gb$, $gb$<p>·     <em>Housekeeper can operate all the appliances and is available to help</em></p>$gb$, $gb$home$gb$, null, null),
  ($gb$montroseterrace-trash-and-recycling$gb$, $gb$Trash & Recycling$gb$, $gb$Local Context$gb$, $gb$<p>·  <em>Housekeeper will take out garbage on a Thursday evening </em></p><p>·  There is <em>no recycling</em></p>$gb$, $gb$home$gb$, null, null),
  ($gb$montroseterrace-tv-operating-instructions$gb$, $gb$TV Operating Instructions$gb$, $gb$Appliances$gb$, $gb$<p>·     <em>TV1 (off Kitchen area) – Turn on TV with Power button. Once TV on Turn on Harman Kardon AV Receiver which switches on surround sound system; TV is automatically in HDMI mode but if not please select this as the source. The Channels & the volume can be changed using the DSTV remote.</em></p><p>·     <em>TV2 (formal lounge) – Turn on TV with Power button. The Channels & the volume can be changed using the DSTV remote.</em></p><p>·     <em>TV3 (downstairs Guest Room) - Turn on TV with Power button. (Channels cannot be changed as it shares DSTV from formal lounge)</em></p><p>·     <em>TV4 (main en suite) - Turn on TV with Power button. (Channels can be changed using DSTV remote but also changes TV in formal lounge)</em></p><p>·     <em>TV5 (Pyjama lounge) - Turn on TV with Power button. (Channels can be changed using DSTV remote but also changes TV1 off Kitchen area)</em></p><p><img src="https://storage.googleapis.com/hostfully-dev-filestack/YMlM7khRr6yzJekn5Oew" style="" width="775" /></p><p><img src="https://storage.googleapis.com/hostfully-dev-filestack/ltf9GopQSfGYnqzYkKlj" /></p><p><img src="https://storage.googleapis.com/hostfully-dev-filestack/d5uHogyETCiiec1weMCP" /></p><p><img src="https://storage.googleapis.com/hostfully-dev-filestack/exIva5ynRdK93KoYd1za" /></p><p><img src="https://storage.googleapis.com/hostfully-dev-filestack/N8VRfWu0TYCaZuyvlYdr" /></p><p><img src="https://storage.googleapis.com/hostfully-dev-filestack/2nxwfWFdQWys36xnDxGN" /></p><p><br /></p>$gb$, $gb$home$gb$, null, null),
  ($gb$montroseterrace-safety$gb$, $gb$Safety$gb$, $gb$Safety$gb$, $gb$<p>· <strong>    <em>Where is the fire extinguisher? </em></strong><em>Pantry</em></p><p>·   <strong>  <em>Where is the gas valve shut-off? </em></strong><em>– Outside scullery behind wooden gate in ventilated area; Extra replacement gas bottles stored in this room</em></p><p>·    <strong> <em>Where is the water shut-off? </em></strong><em>Municipal valve is located on site boundary on extreme left of property as you face the house from the road side</em></p><p>·     <strong><em>Where is the circuit board?</em></strong><em> Main DB Board is in the garage and secondary board is in pool pump room. The Backup power supply is located below DB board.</em></p>$gb$, $gb$alert$gb$, null, $gb$gas-shut-off$gb$),
  ($gb$montroseterrace-garden-and-pool$gb$, $gb$Garden and Pool$gb$, $gb$Outdoors$gb$, $gb$<p><strong>·     <em>Irrigation system</em></strong><em> –Set to automatically irrigate at 7am every morning and lasts for approx 90mins</em></p><p>·     <em>Pool company maintains the pool every Friday – Poolside Services (021 6710883)</em></p><p><br /></p><p><span class="ql-cursor">﻿</span>Pool Towels are kept in a basket in the laundry or at the pool. They will be washed and dried after every use at the end of the day. </p>$gb$, $gb$pool$gb$, null, null),
  ($gb$montroseterrace-emergencies-hospital-and-safety$gb$, $gb$Emergencies - Hospital and Safety$gb$, $gb$Emergencies$gb$, $gb$<p><span style="color: rgb(41, 50, 64);">The nearest Hospital is </span><a href="http://www.mediclinic.co.za/Hospitals/HospitalDetails/id/3" target="_blank" style="color: rgb(0, 102, 204); background-color: rgb(255, 255, 255);"><strong>Mediclinic Constantiaberg</strong></a>.</p><p>Alternative Hospitals</p><p>Tokai Melomed - https://www.melomed.co.za/melomedtokai.asp</p><p>Kingsbury (Claremont) - https://www.lifehealthcare.co.za/hospitals/western-cape/cape-town/life-kingsbury-hospital/</p><p>Medi Clinic (Cape Town) - https://www.mediclinic.co.za/en/cape-town/contact.html</p><p><br /></p><p><strong>Paramedics</strong></p><ul><li>EMT / Private / Southern Suburbs:<strong> +27 72 236 8368</strong></li><li>Netcare 911 / Private / All areas:<strong> +27 82 911</strong></li></ul><p><br /></p><p><strong>Emergency Numbers</strong></p><ul><li><span style="color: rgba(0, 0, 0, 0.87);">Medical, Police, and Fire Emergencies: </span><strong style="color: rgba(0, 0, 0, 0.87);">+27 86 12 12 300</strong></li></ul><p><br /></p><p><strong>Doctors</strong></p><p>&gt; <a href="http://tokaimedical.co.za/" target="_blank" style="background-color: rgb(255, 255, 255); color: rgb(0, 102, 204);"><strong>Dr. Dion O'Cuinnegan</strong></a> // +27 <span style="color: rgba(0, 0, 0, 0.87);">21 712 9367 // 3 Susan Way, Tokai, 7966</span></p><ul><li>General Practitioner, great with children and they do house calls.</li></ul><p><br /></p><p>&gt; <a href="https://www.drcohen.co.za/" target="_blank" style="background-color: rgb(255, 255, 255); color: rgb(0, 102, 204);"><strong>Dr. Cohen & Associates</strong></a> // +27 <span style="color: rgba(0, 0, 0, 0.87);">21 794 1703 // </span>4 Walloon Road, Constantia, 7806</p><ul><li><span style="color: rgb(33, 33, 33);">Routine general medical care, as well as a range of specialist services.</span></li></ul><p><br /></p><p>&gt; <a href="http://copperfieldchildcare.co.za/doctor/dr-hedi-hedwig-van-der-watt" target="_blank" style="background-color: rgb(255, 255, 255); color: rgb(0, 102, 204);"><strong>Dr. Hedi van der Watt</strong></a> // +27 21 761 3408 // <span style="color: rgb(34, 34, 34);">226 Main Road, Claremont, 7708</span></p><ul><li>Healthcare Practitioner, specialising as a Paediatrician.</li></ul>$gb$, $gb$hospital$gb$, null, null),
  ($gb$montroseterrace-online-grocery-shopping$gb$, $gb$Online Grocery Shopping$gb$, $gb$Local Context$gb$, $gb$<p>If you'd like to do a shop for delivery on the day you arrive, I recommend:</p><p><br /></p><p><strong style="background-color: transparent;">Checkers </strong>have an app called Sixty60 and they deliver within an hour - https://www.checkers.co.za/</p><p><strong>Woolworths</strong> has an app called Dash and they also claim to deliver within an hour - https://www.woolworths.co.za/cat/_/N-1oqo8fi</p><p><a href="https://www.pnp.co.za/" target="_blank" style="color: black; background-color: rgb(255, 255, 255);"><strong>Pick n Pay</strong></a><span style="color: rgba(0, 0, 0, 0.87);"> - Basics and Alcohol - </span>https://www.pnp.co.za/asap-same-day-delivery</p>$gb$, $gb$shopping-cart$gb$, null, null),
  ($gb$montroseterrace-laundry-service$gb$, $gb$Laundry Service$gb$, $gb$Appliances$gb$, $gb$<p>*Please note that all laundry done by the housekeeper is at <strong>your own risk</strong>.</p><p>*The homeowner is <strong>not liable</strong> for any damages to your clothing.</p><p>The cleaning staff can do maximum of two loads of washing per day that they work. please indicate if you would like them to assist with ironing</p>$gb$, $gb$washing-machine$gb$, null, null),
  ($gb$montroseterrace-loadshedding$gb$, $gb$Loadshedding$gb$, $gb$Local Context$gb$, $gb$<p>· <em>There is an Inverter with battery backup in the garage below the Main Electrical DB Board. It will kick in automatically if there is a power failure. The inverter provides back up for all lights in the house including all kitchen appliances however care must e taken not to use appliances simultaneously especially the oven/kettle/airfryer (high wattage equipment). Aircons and certain of the TV’s are not connected including not all plug points</em></p><p><br /></p><p>The alarm and gates will operate as normal during a power outage. If there is an issue with the gate, the housekeeper does have a key to manually operate the gate</p><p><br /></p><p>* Your homes are prepared for load-shedding, even though it is inconvenient.</p><p>* I would advise you to download the App - <a href="https://play.google.com/store/apps/details?id=com.ashwhale.sepush.eskom&hl=en_ZA&gl=US" target="_blank">Eskom Se Push</a></p><ul><li>Constantia - Zone 11</li><li>Bishopscourt - Zone 11</li><li>Hout Bay - Zone 11</li><li>Tokai - Zone 8</li><li>Camps Bay - Zone 7</li><li>Hermanus - Zone 3</li><li>Onrus - Zone 6</li></ul><p><br /></p><p>* Sometimes when the power goes off or comes back on again, alarms tend to go off... It's best to know when it's coming, so that you can either be away or prepared for it.</p><p><span style="color: rgba(0, 0, 0, 0.87);">We hope this doesn't affect your stay too much!</span></p>$gb$, $gb$bolt$gb$, null, null),
  ($gb$montroseterrace-suntan-lotion-self-tanning-spray$gb$, $gb$Suntan Lotion / Self Tanning Spray$gb$, $gb$House Rules$gb$, $gb$<p>We often have problems with suntan lotion and self-tanning sprays <strong style="color: rgb(230, 0, 0);">staining</strong><span style="color: rgb(230, 0, 0);"> </span>loungers and bed linen, therefore:</p><p><br /></p><p>&gt; Please ensure that you <strong><u>lie on the towels provided</u></strong><u> </u>on the sun loungers.</p><p>&gt; Please<span style="color: rgb(230, 0, 0);"> </span><strong style="color: rgb(230, 0, 0);"><u>DO NOT</u></strong> lie on the bed linen while wearing sun-tan lotion / self-tanning spray.</p>$gb$, $gb$sun$gb$, null, null),
  ($gb$montroseterrace-transportation$gb$, $gb$Transportation$gb$, $gb$Local Context$gb$, $gb$<p>LTC Luxury Shuttle and Adventures: +27 79 444 9481</p><p>Jordan: +27 72 311 6565</p><p>Nagel Transport: +21 797 6406</p><p>Francis - +27 62 165 6417</p><p>*Alternatively, you can use<strong> Uber</strong> or <strong>Bolt </strong>to get around Cape Town.</p>$gb$, $gb$car$gb$, null, null);

