  ($gb$montroseterrace-incognito-bar$gb$, $gb$Incognito - Bar$gb$, $gb$bars$gb$, $gb$<p>Upmarket Bar in Constantia </p>$gb$, $gb$The Alphen Boutique Hotel, Alphen Dr, Constantia, Cape Town, 7806, South Africa$gb$, $gb$+27 21 795 6300$gb$, $gb$https://www.kovecollection.co.za/incognito/$gb$, $gb$https://storage.googleapis.com/hostfully-dev-filestack/0m0PQQqKRd2F6LhRCqfd$gb$, -34.0128501, 18.4506976),
  ($gb$montroseterrace-iziko-bo-kaap-museum$gb$, $gb$Iziko Bo-Kaap Museum$gb$, $gb$attractions$gb$, $gb$<p>The Iziko South African Museum is a South African national museum located in Cape Town. The museum was founded in 1825, the first in the country. It has been on its present site in the Company's Garden since 1897. The museum houses important African zoology, palaeontology and archaeology collections. </p>$gb$, $gb$71 Wale St, Schotsche Kloof, Cape Town, 8001, South Africa$gb$, $gb$021 481 3938$gb$, $gb$https://www.iziko.org.za/museums/bo-kaap-museum/$gb$, $gb$https://storage.googleapis.com/hostfully-dev-filestack/JyfrEaU8Q6yCmCFCAnVJ$gb$, -33.9215332, 18.4149866),
  ($gb$montroseterrace-jack-black-brewing-company$gb$, $gb$Jack Black Brewing Company$gb$, $gb$bars$gb$, $gb$<p>Dedicated to brewing beers that inspire us. Our focus is flavour and our philosophy is to innovate while staying true to traditional, hand-crafted methods.</p>$gb$, $gb$10 Brigid Rd, Diep River, Cape Town, 7945, South Africa$gb$, $gb$021 447 4151$gb$, $gb$https://www.jackblackbeer.com/brewery/$gb$, $gb$https://storage.googleapis.com/hostfully-dev-filestack/cKcpP4SxQeWs41Gd1OQo$gb$, -34.03978529999999, 18.4798468),
